#&gt; [1] "R/rd-to-list.R"
#&gt; 
#&gt; $name
#&gt; [1] "rd_to_list"
#&gt; 
#&gt; $alias
#&gt; [1] "rd_to_list"
#&gt; 
#&gt; $title
#&gt; [1] "Converts a given 'Rd' file into a list object"
#&gt; 
#&gt; $usage
#&gt; [1] "rd_to_list(rd_file, project = \".\", pkg = NULL)"
#&gt; 
#&gt; $arguments
#&gt; $arguments[[1]]
#&gt; $arguments[[1]]$argument
#&gt; [1] "rd_file"
#&gt; 
