#&gt; 
#&gt; $arguments[[2]]$description
#&gt; [1] "The path to the root folder of the project."
#&gt; 
#&gt; 
#&gt; $arguments[[3]]
#&gt; $arguments[[3]]$argument
#&gt; [1] "pkg"
#&gt; 
